// Some portions generated by Co-Pilot
import React from "react";
import { render, cleanup } from "@testing-library/react";
import { describe, it, expect, vi, afterEach } from "vitest";
import ReleaseSelector from "../index";

vi.mock("@/components/Common/SelectorHeader", () => ({
  default: ({ title, data }: { title: string[]; data: unknown[][] }) => (
    <div data-testid="selector-header">
      {title.map((t, i) => (
        <div key={i} data-testid={`selector-title-${i}`}>
          {t}
        </div>
      ))}
      <div data-testid="selector-data-count">{data.length}</div>
    </div>
  ),
}));

vi.mock("@/hooks/fetchConstants", () => ({
  useOses: () => [
    { name: "Linux", value: "linux" },
    { name: "Mac", value: "mac" },
    { name: "Windows", value: "windows" },
    { name: "Alpine-linux", value: "alpine-linux" },
    { name: "Aix", value: "aix" },
    { name: "Solaris", value: "solaris" },
  ],
  useArches: () => [
    { name: "x64", value: "x64" },
    { name: "aarch64", value: "aarch64" },
    { name: "arm", value: "arm" },
    { name: "ppc64le", value: "ppc64le" },
    { name: "s390x", value: "s390x" },
  ],
}));

const defaultVersions = [
  { name: "21", value: "21" },
  { name: "17", value: "17" },
  { name: "11", value: "11" },
];

describe("ReleaseSelector", () => {
  afterEach(() => {
    cleanup();
  });

  it("renders correctly with default props", () => {
    const { getByTestId } = render(
      <ReleaseSelector
        versions={defaultVersions}
        updateVersion={vi.fn()}
        updateOS={vi.fn()}
        updateArch={vi.fn()}
      />,
    );
    expect(getByTestId("selector-header")).toBeTruthy();
  });

  it("renders 3 selectors in non-marketplace mode", () => {
    const { getByTestId } = render(
      <ReleaseSelector
        versions={defaultVersions}
        updateVersion={vi.fn()}
        updateOS={vi.fn()}
        updateArch={vi.fn()}
      />,
    );
    // In non-marketplace mode, there are 3 selectors (OS, Arch, Version)
    expect(getByTestId("selector-data-count").textContent).toBe("3");
  });

  it("renders 4 selectors in marketplace mode", () => {
    const { getByTestId } = render(
      <ReleaseSelector
        marketplace
        versions={defaultVersions}
        updateVersion={vi.fn()}
        updateOS={vi.fn()}
        updateArch={vi.fn()}
        updatePackageType={vi.fn()}
        defaultPackageType="jdk"
      />,
    );
    // In marketplace mode, there are 4 selectors (OS, Arch, Version, PackageType)
    expect(getByTestId("selector-data-count").textContent).toBe("4");
  });

  it("calls updateOS when OS changes", () => {
    const updateOS = vi.fn();
    render(
      <ReleaseSelector
        versions={defaultVersions}
        updateVersion={vi.fn()}
        updateOS={updateOS}
        updateArch={vi.fn()}
        defaultOS="linux"
      />,
    );
    // Component renders without errors with defaultOS
    expect(updateOS).not.toHaveBeenCalled();
  });

  it("renders with default values", () => {
    const { getByTestId } = render(
      <ReleaseSelector
        versions={defaultVersions}
        updateVersion={vi.fn()}
        updateOS={vi.fn()}
        updateArch={vi.fn()}
        defaultVersion="21"
        defaultOS="linux"
        defaultArch="x64"
      />,
    );
    expect(getByTestId("selector-header")).toBeTruthy();
  });

  it("renders correctly with no default values", () => {
    const { getByTestId } = render(
      <ReleaseSelector
        versions={defaultVersions}
        updateVersion={vi.fn()}
        updateOS={vi.fn()}
        updateArch={vi.fn()}
      />,
    );
    expect(getByTestId("selector-header")).toBeTruthy();
  });
});
